// src/components/PleadingsPage.jsx
import React from 'react';
import PleadingCard from './PleadingCard';

const PleadingsPage = () => {
  const pleadings = [
    {
      title: "42-B Eligibility Check",
      description: "Initial verification process for 42-B eligibility",
      date: "Standard Protocol",
      status: "Important",
      route: "/pleadings/42b-eligibility-check"
    },
    {
      title: "Case Type Guidelines",
      description: "Procedures for different case types and locations",
      date: "Updated: January 2024",
      status: "Standard",
      route: "/pleadings/case-type-guidelines"
    },
    {
      title: "NTA Response Templates",
      description: "Templates for responding to Notice to Appear",
      date: "Added: December 2023",
      status: "New",
      route: "/pleadings/nta-templates"
    },
    {
      title: "Special Cases",
      description: "Guidelines for Cuban, Venezuelan, Haitian, and Ukrainian cases",
      date: "Updated: January 2024",
      status: "Updated",
      route: "/pleadings/special-cases"
    },
    {
      title: "Information Pleadings",
      description: "Initial verification process for 42-B eligibility",
      date: "Standard Protocol",
      status: "Important",
      route: "/pleadings/information-pleadings"
    }
  ];

  return (
    <div className="space-y-8">
      <div>
        <h1 className="text-3xl font-bold text-gray-900 dark:text-white mb-4">
          Pleadings
        </h1>
        <p className="text-gray-600 dark:text-gray-400 max-w-3xl">
          Access comprehensive information about legal pleadings, including templates, 
          guidelines, and best practices for various types of legal documents.
        </p>
      </div>

      <div className="grid gap-6">
        {pleadings.map((pleading, index) => (
          <PleadingCard key={index} {...pleading} />
        ))}
      </div>
    </div>
  );
};

export default PleadingsPage;
